+export interface DurationObservation {
+  duration: number
+  recordedAt: number
+}
+
+export function smoothDurations(observations: DurationObservation[], smoothing: 'latest' | 'average' | 'p95' | 'median'): number {
+  if (!observations.length) return 0
+  if (smoothing === 'latest') return observations.reduce((latest, item) => item.recordedAt > latest.recordedAt ? item : latest).duration
+  const durations = observations.map(item => item.duration).sort((a, b) => a - b)
+  if (smoothing === 'average') return Math.round(durations.reduce((sum, duration) => sum + duration, 0) / durations.length)
+  if (smoothing === 'p95') return durations[Math.ceil(0.95 * durations.length) - 1]
+  const middle = Math.floor(durations.length / 2)
+  return durations.length % 2 ? durations[middle] : Math.floor((durations[middle - 1] + durations[middle]) / 2)
+}
