+import { mkdir, readFile, writeFile } from 'node:fs/promises'
+import { dirname } from 'pathe'
+import type { DurationObservation } from './duration-smoothing'
+
+export type DurationHistory = Record<string, DurationObservation[]>
+
+function observations(value: unknown): DurationObservation[] | null {
+  const entries = typeof value === 'number' ? [{ duration: value, recordedAt: 0 }] : typeof value === 'object' && value !== null && 'observations' in value ? (value as { observations: unknown }).observations : [value]
+  if (!Array.isArray(entries) || entries.some(item => !item || typeof item !== 'object' || !Number.isFinite((item as DurationObservation).duration) || !Number.isFinite((item as DurationObservation).recordedAt))) return null
+  return entries as DurationObservation[]
+}
+
+export async function readDurationHistory(path: string, ttl: number): Promise<DurationHistory | null> {
+  try {
+    const raw = JSON.parse(await readFile(path, 'utf8'))
+    if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return null
+    const expiry = Date.now() - ttl
+    const history: DurationHistory = {}
+    for (const [file, value] of Object.entries(raw)) {
+      const values = observations(value)
+      if (!values) return null
+      history[file] = ttl > 0 ? values.filter(item => item.recordedAt === 0 || item.recordedAt >= expiry) : values
+    }
+    return history
+  }
+  catch {
+    return null
+  }
+}
+
+export async function writeDurationHistory(path: string, previous: DurationHistory | null, updates: Record<string, number>, maxRuns: number): Promise<void> {
+  const now = Date.now()
+  const history = previous || {}
+  for (const [file, duration] of Object.entries(updates)) {
+    history[file] = [...(history[file] || []), { duration, recordedAt: now }]
+      .sort((a, b) => b.recordedAt - a.recordedAt)
+      .slice(0, maxRuns)
+  }
+  const output = Object.fromEntries(Object.entries(history).map(([file, values]) => [file, maxRuns === 1 ? values[0] : { observations: values }]))
+  await mkdir(dirname(path), { recursive: true })
+  await writeFile(path, `${JSON.stringify(output, null, 2)}\
`)
