+export function warnOnImbalance(loads: number[], threshold: number, warn: (message: string) => void): void {
+  if (!threshold || !loads.length) return
+  const max = Math.max(...loads)
+  const ratio = max ? Math.min(...loads) / max : 1
+  if (ratio < threshold) warn(`Shard duration imbalance: ratio=${ratio.toFixed(2)} threshold=${threshold.toFixed(2)}`)
